import {
  Mjml,
  MjmlBody,
  MjmlFont,
  MjmlHead,
  MjmlPreview,
  MjmlStyle,
  MjmlWrapper,
} from "@faire/mjml-react";
import type { ReactNode } from "react";

import { defaultTheme } from "@/components/email/theme-default";
import type { EmailThemeTokens } from "@/components/email/theme-default";
import {
  buttonsResponsiveStyles,
  ButtonsSection,
} from "@/components/email/buttons-shared";
import type {
  ButtonsVariant,
  ButtonSize,
} from "@/components/email/buttons-shared";

export interface ButtonsProps {
  align?: "center" | "left" | "right";
  href?: string;
  icon?: ReactNode;
  iconPosition?: "leading" | "trailing";
  label?: string;
  size?: ButtonSize | "all";
  theme?: EmailThemeTokens;
  variant?: ButtonsVariant;
}

export { ButtonsSection };
export type { ButtonsVariant, ButtonSize };

export const Buttons = ({ theme = defaultTheme, ...props }: ButtonsProps) => (
  <Mjml>
    <MjmlHead>
      <MjmlPreview>Buttons</MjmlPreview>
      <MjmlFont href="https://rsms.me/inter/inter.css" name="Inter" />
      <MjmlStyle>{buttonsResponsiveStyles}</MjmlStyle>
    </MjmlHead>
    <MjmlBody width={theme.containerWidth}>
      <MjmlWrapper padding="0">
        <ButtonsSection {...props} />
      </MjmlWrapper>
    </MjmlBody>
  </Mjml>
);

Buttons.PreviewProps = {
  align: "center",
  href: "https://example.com",
  size: "all",
  theme: defaultTheme,
  variant: "primary",
} satisfies ButtonsProps;
